{
 "level": "A2",
 "intro": "In this topic you will learn how to use <strong>somewhere, anywhere, nowhere, everywhere</strong> correctly in affirmations, negations and questions.",
 "rules": [
 {
 "label": "Assertions",
 "color": "emerald",
 "text": "<strong>Somewhere</strong> - \"somewhere\" in statements:",
 "example": "I live somewhere near here."
 },
 {
 "label": "Negatives / questions",
 "color": "blue",
 "text": "<strong>Anywhere</strong> - in negatives and questions:",
 "example": "I don’t live anywhere near here."
 },
 {
 "label": "One word negation",
 "color": "rose",
 "text": "<strong>Nowhere</strong> - one word negation:",
 "example": "I live nowhere near here."
 }
 ]
}

{
 "title": "1. Forms and Translation",
 "intro": "Here are the four main place words from <code class=\"font-mono text-xs\">some / any</code>:",
 "items": [
 {
 "label": "Assertion",
 "title": "somewhere",
 "subtitle": "somewhere"
 },
 {
 "label": "Negation / question",
 "title": "anywhere",
 "subtitle": "somewhere / nowhere (in negatives and questions)"
 },
 {
 "label": "Negation",
 "title": "nowhere",
 "subtitle": "nowhere"
 },
 {
 "label": "Generalization",
 "title": "everywhere",
 "subtitle": "everywhere"
 }
 ]
}

{
 "title": "2. Use in affirmations, negatives and questions",
 "sections": [
 {
 "label": "Statements",
 "color": "emerald",
 "description": "In statements, we usually use <strong>somewhere</strong> and <strong>everywhere</strong>.",
 "examples": [
 {
 "en": "He is somewhere in the building.",
 "ua": "He is somewhere in the building."
 },
 {
 "en": "You can see flowers everywhere in spring.",
 "ua": "You can see flowers everywhere in spring."
 }
 ]
 },
 {
 "label": "Negatives",
 "color": "rose",
 "description": "In negatives, use <strong>anywhere</strong> with <code class=\"font-mono text-xs\">don’t/doesn’t</code>, or use <strong>nowhere</strong> without an extra not.",
 "examples": [
 {
 "en": "I don’t go anywhere on Sundays.",
 "ua": "I don’t go anywhere on Sundays."
 },
 {
 "en": "I go nowhere on Sundays.",
 "ua": "I go nowhere on Sundays."
 }
 ],
 "note": "❗ Avoid double negatives like <span class=\"line-through\">I don’t go nowhere</span>."
 },
 {
 "label": "Questions",
 "color": "sky",
 "description": "In questions we usually use <strong>anywhere</strong>.",
 "examples": [
 {
 "en": "Do you go anywhere on Sundays?",
 "ua": "Do you go anywhere on Sundays?"
 },
 {
 "en": "Is there anywhere to eat near here?",
 "ua": "Is there anywhere to eat near here?"
 }
 ],
 "note": "<span class=\"font-semibold\">Somewhere</span> in the question it sounds like you expect \"some specific place\"."
 }
 ]
}

{
 "title": "3. Anywhere vs Nowhere",
 "intro": "<strong>Two different grammatical forms - same meaning</strong> in normal English:",
 "rows": [
 {
 "en": "I don’t go anywhere on Sundays.",
 "ua": "I don’t go anywhere on Sundays.",
 "note": "Negation via <code class=\"font-mono text-xs\">don't</code> + <strong>anywhere</strong>."
 },
 {
 "en": "I go nowhere on Sundays.",
 "ua": "I go nowhere on Sundays.",
 "note": "One-word negation <strong>nowhere</strong>, without <code class=\"font-mono text-xs\">don't</code>."
 }
 ],
 "warning": "❗ <span class=\"line-through\">I don’t go nowhere</span> is grammatically incorrect in standard English (it is a double negative)."
}

{
 "title": "4. Common mistakes",
 "items": [
 {
 "label": "Mistake 1",
 "color": "rose",
 "title": "Do not use two negatives in one sentence.",
 "wrong": "I don't go nowhere.",
 "right": "✅ <span class=\"font-mono\">I don't go anywhere.</span> / <span class=\"font-mono\">I go nowhere.</span>"
 },
 {
 "label": "Mistake 2",
 "color": "amber",
 "title": "Choose anywhere for neutral questions.",
 "hint": "<span class=\"font-mono\">Do you go somewhere on Sundays?</span> can sound like you have a specific place in mind.<br>For an open question, use <span class=\"font-mono\">Do you go anywhere on Sundays?</span>"
 },
 {
 "label": "Mistake 3",
 "color": "sky",
 "title": "Do not use everywhere when you mean one unknown place.",
 "hint": "<span class=\"font-mono\">I want to go everywhere in London</span> means every place. For one unknown place, say <span class=\"font-mono\">I want to go somewhere in London.</span>"
 }
 ]
}

{
 "title": "5. Short summary",
 "items": [
 "<strong>Somewhere</strong> means an unknown or unnamed place, usually in statements.",
 "<strong>Anywhere</strong> is common in questions and negatives; in statements it can mean any place.",
 "<strong>Nowhere</strong> already means no place, so do not add another negative.",
 "<strong>Everywhere</strong> means all places or in every place.",
 "Say <span class=\"font-mono text-xs\">I don't go anywhere</span> or <span class=\"font-mono text-xs\">I go nowhere</span>, not both negatives together."
 ]
}

{
 "title": "6. Practice",
 "select_title": "Exercise 1. Choose the correct word",
 "select_intro": "Choose <strong>somewhere / anywhere / nowhere / everywhere</strong>.",
 "selects": [
 {
 "label": "I can’t find my keys <span class=\"text-slate-500\">(= in no place)</span>.",
 "prompt": "I can’t find my keys ______."
 },
 {
 "label": "She wants to live <span class=\"text-slate-500\">(somewhere near the sea)</span>.",
 "prompt": "She wants to live ______ near the sea."
 },
 {
 "label": "Do you want to go <span class=\"text-slate-500\">(somewhere)</span> this evening?",
 "prompt": "Do you want to go ______ this evening?"
 }
 ],
 "options": [
 "somewhere",
 "anywhere",
 "nowhere",
 "everywhere"
 ],
 "input_title": "Exercise 2. Fill in the blanks",
 "input_intro": "Write <strong>somewhere / anywhere / nowhere / everywhere</strong>.",
 "inputs": [
 {
 "before": "I don’t want to go",
 "after": "tonight."
 },
 {
 "before": "There is",
 "after": "to sit in this park. It’s full."
 },
 {
 "before": "He travels",
 "after": "for work."
 }
 ],
 "rephrase_title": "Exercise 3. Rephrase",
 "rephrase_intro": "Rewrite the sentence using <strong>anywhere / nowhere</strong>.",
 "rephrase": [
 {
 "example_label": "Example:",
 "example_original": "I don’t go anywhere on Saturdays.",
 "example_target": "I go nowhere on Saturdays."
 },
 {
 "original": "1. I go nowhere on Friday evenings.",
 "placeholder": "Write the same meaning with don’t ... anywhere"
 },
 {
 "original": "2. She doesn’t go anywhere without her phone.",
 "placeholder": "Try paraphrasing with nowhere"
 }
 ]
}

